hooks.command:
if git -C "$CLAUDE_PROJECT_DIR" diff --quiet && git -C "$CLAUDE_PROJECT_DIR" diff --staged --quiet; then OUT=$(git -C "$CLAUDE_PROJECT_DIR" pull --rebase origin main 2>&1 | tail -2 | tr '
' ' '); printf '{"systemMessage":"git pull: %s"}
' "$OUT"; else git -C "$CLAUDE_PROJECT_DIR" fetch origin main 2>/dev/null; BEHIND=$(git -C "$CLAUDE_PROJECT_DIR" rev-list HEAD..origin/main --count 2>/dev/null || echo 0); if [ "$BEHIND" -gt 0 ]; then printf '{"systemMessage":"⚠️  %s commit(s) behind origin/main + uncommitted local changes — stash & pull when stable"}
' "$BEHIND"; fi; fi
